func (m repositoryMods) WithParentsCascading() RepositoryMod {
	return RepositoryModFunc(func(ctx context.Context, o *RepositoryTemplate) {
		if isDone, _ := repositoryWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = repositoryWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewUserAccountWithContext(ctx, UserAccountMods.WithParentsCascading())
			m.WithCreatedByUserAccount(related).Apply(ctx, o)
		}
		{

			related := o.f.NewOrganizationWithContext(ctx, OrganizationMods.WithParentsCascading())
			m.WithOrganization(related).Apply(ctx, o)
		}
		{

			related := o.f.NewUserAccountWithContext(ctx, UserAccountMods.WithParentsCascading())
			m.WithUpdatedByUserAccount(related).Apply(ctx, o)
		}
	})
}

